module tb_top;

parameter L1_IN      = 784;
parameter L1_OUT     = 128;
parameter L2_IN      = 128;
parameter L2_OUT     = 10;
parameter PES        = 8;
parameter TSTEPS     = 20;  // Matches 20 timesteps
parameter DATA_WIDTH = 8;
parameter ACC_WIDTH  = 16;
parameter THRESHOLD  = 283;

reg          clk;
reg          reset_n;
reg          start;
reg [783:0]  input_spikes;

wire [3:0]   predicted_class;
wire         done;

//  instantiate top 
top #(
    .L1_IN      (L1_IN),
    .L1_OUT     (L1_OUT),
    .L2_IN      (L2_IN),
    .L2_OUT     (L2_OUT),
    .PES        (PES),
    .TSTEPS     (TSTEPS),
    .DATA_WIDTH (DATA_WIDTH),
    .ACC_WIDTH  (ACC_WIDTH),
    .THRESHOLD  (THRESHOLD)
) dut (
    .clk            (clk),
    .reset_n        (reset_n),
    .start          (start),
    .input_spikes   (input_spikes),
    .predicted_class(predicted_class),
    .done           (done)
);

// clock
initial clk = 0;
always #5 clk = ~clk;

// spike trains for all 20 timesteps 
reg [783:0] spike_train [0:19];

initial begin
    spike_train[0] = 784';
    spike_train[1] = 784';
    spike_train[2] = 784';
    spike_train[3] = 784';
    spike_train[4] = 784';
    spike_train[5] = 784';
    spike_train[6] = 784';
    spike_train[7] = 784';
    spike_train[8] = 784';
    spike_train[9] = 784';
    spike_train[10] = 784';
    spike_train[11] = 784';
    spike_train[12] = 784';
    spike_train[13] = 784';
    spike_train[14] = 784';
    spike_train[15] = 784';
    spike_train[16] = 784';
    spike_train[17] = 784';
    spike_train[18] = 784';
    spike_train[19] = 784';

            
end

// feed correct spike train using the controller's internal timestep 
always @(*) begin
    if (dut.ctrl.timestep < TSTEPS)
        input_spikes = spike_train[dut.ctrl.timestep];
    else
        input_spikes = 0;
end

// main test
initial begin
    reset_n      = 0;
    start        = 0;
    input_spikes = 0;

    repeat(5) @(posedge clk);
    #1;
    reset_n = 1;

    repeat(2) @(posedge clk);
    #1;

    // TEST 1: full inference 
    $display("=== TEST 1: full inference ===");
    
    @(negedge clk);
    start = 1;
    @(posedge clk);
    #1;
    start = 0;

    wait(done == 1);
    #1;

    $display("predicted class = %0d", predicted_class);

    // TEST 2: reset and rerun
    $display("=== TEST 2: reset and rerun same image ===");
    @(negedge clk);
    reset_n = 0;
    repeat(3) @(posedge clk);
    #1;
    reset_n = 1;
    repeat(2) @(posedge clk);
    #1;

    @(negedge clk);
    start = 1;
    @(posedge clk);
    #1;
    start = 0;

    wait(done == 1);
    #1;
    $display("predicted class = %0d", predicted_class);
    $display("=== FINAL SPIKE COUNTS ===");
    $display("Class 0: %0d", dut.output_membrane[0]);
    $display("Class 1: %0d", dut.output_membrane[1]);
    $display("Class 2: %0d", dut.output_membrane[2]);
    $display("Class 3: %0d", dut.output_membrane[3]);
    $display("Class 4: %0d", dut.output_membrane[4]);
    $display("Class 5: %0d", dut.output_membrane[5]);
    $display("Class 6: %0d", dut.output_membrane[6]);
    $display("Class 7: %0d", dut.output_membrane[7]);
    $display("Class 8: %0d", dut.output_membrane[8]);
    $display("Class 9: %0d", dut.output_membrane[9]);

    $display("=== ALL TESTS DONE ===");
    #20;
    $finish;
end

    //  LAYER 1 DIAGNOSTIC MONITOR
always @(posedge clk) begin
    // When Layer 1 neurons are enabled, print the current from the first two PEs
    if (dut.neuron_en && ~dut.layer_sel) begin
        $display("Layer 1, Group %0d -> PE0 Current: %0d | PE1 Current: %0d", 
                 dut.group, dut.layer1.cur[0], dut.layer1.cur[1]);
    end
end

// timeout
initial begin
    #10000000; // Increased timeout for 20 timesteps
    $display("TIMEOUT — check FSM is not stuck");
    $finish;
end

initial begin
    $dumpfile("tb_top.vcd");
    $dumpvars(0, tb_top);
end

endmodule
